def get_category_by_id(category_id):
    return next((c for c in CATEGORIES if c["id"] == category_id), None)


def get_product_by_id(product_id):
    return next((p for p in PRODUCTS if p["id"] == product_id), None)


class Query(graphene.ObjectType):
    products = graphene.List(Product, category_id=graphene.ID(), min_price=graphene.Float(), max_price=graphene.Float())
    product = graphene.Field(Product, id=graphene.ID(required=True))
    categories = graphene.List(Category)
    category = graphene.Field(Category, id=graphene.ID(required=True))
    reviews = graphene.List(Review, product_id=graphene.ID())
    review = graphene.Field(Review, id=graphene.ID(required=True))

    def resolve_products(self, info, category_id=None, min_price=None, max_price=None):
        results = PRODUCTS
        if category_id is not None:
            results = [p for p in results if p["category_id"] == category_id]
        if min_price is not None:
            results = [p for p in results if p["price"] >= min_price]
        if max_price is not None:
            results = [p for p in results if p["price"] <= max_price]
        return results

    def resolve_product(self, info, id):
        return get_product_by_id(id)

    def resolve_categories(self, info):
        return CATEGORIES

    def resolve_category(self, info, id):
        return get_category_by_id(id)

    def resolve_reviews(self, info, product_id=None):
        if product_id is not None:
            return [r for r in REVIEWS if r["product_id"] == product_id]
        return REVIEWS

    def resolve_review(self, info, id):
        return next((r for r in REVIEWS if r["id"] == id), None)


def resolve_product_category(product, info):
    return get_category_by_id(product["category_id"])


def resolve_product_reviews(product, info):
    return [r for r in REVIEWS if r["product_id"] == product["id"]]


Product.resolve_category = resolve_product_category
Product.resolve_reviews = resolve_product_reviews

schema = graphene.Schema(query=Query)

app = Flask(__name__)
app.add_url_rule(
    "/graphql",
    view_func=GraphQLView.as_view(
        "graphql",
        schema=schema,
        graphiql=True,
    ),
)

if __name__ == "__main__":
    app.run(debug=True)